INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('c5e74762-b53c-47ab-8a69-502ab76971a7', 'Feature', 'New capability or enhancement', '#10B981', '✨', '{"pattern":"[Added/Introduced] + [capability] + [for whom or why]","example":"Added dark mode toggle to the settings page for improved accessibility","whenToUse":"Use when shipping a new capability, UI addition, or user-facing enhancement","contentHints":"Describe what changed, how users access it, and any migration steps. Screenshots or before/after comparisons work well."}', 1, 0, '2026-03-20T09:03:13.866Z', '2026-03-20T09:03:13.866Z');
