INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('e24b9191-0d25-46c0-8fb2-a0acf876db79', 'Breaking Change', 'Incompatible change requiring user action', '#EF4444', '💥', '{"pattern":"[Breaking] + [what changed] + [migration path]","example":"Breaking: Renamed /api/v1/users to /api/v2/accounts — update all client references","whenToUse":"Use when a change requires users to update their code, config, or workflow","contentHints":"Clearly state what breaks, who is affected, the migration path, and a deadline if applicable. Use a diff block for code changes."}', 1, 2, '2026-03-20T09:03:13.866Z', '2026-03-20T09:03:13.866Z');
