-- changelog-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Changelog', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Release notes and change history', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Lead with the action verb (Added, Fixed, Breaking, Improved, Deprecated). Be specific about what changed."},"content":{"tips":"Write for users who need to know if this change affects them. Include migration steps for breaking changes."},"formatting":["Bullet lists: group related sub-changes within a release","Code blocks: API changes, config diffs, migration commands","Tables: before/after comparisons for breaking changes","Bold: highlight the action verb and affected component","Headings: separate Description, Migration, and Impact sections"],"avoid":["Internal jargon that users cannot act on","Vague descriptions like \"various improvements\"","Missing migration steps for breaking changes"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":50,"max":10000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
